import re

from pathlib import Path


class LasFilename:
    """Class meant to parse geosat's file (generally .laz) where the 'strada_name'
    and the starting distance in said strada are encoded in the filename


    Eg:
        CN_223_0+000_0+050.laz is the name of a laz file for the strada "CN_223"
        starting at the 0th meter and ending at the 50th meter of the road.
    """

    STRADA_RE = r"(?:.*[\\/])?(?P<strada>.*?)"
    LOT_RE = r"(?:(?:_lot_)(?P<lot>[0-9]+))?"
    DISTANCE_RE = r"([0-9]+)\+([0-9]+)_([0-9]+)\+([0-9]+)"

    matcher = re.compile(
        f"{STRADA_RE}{LOT_RE}_(?:[RF]_)?{DISTANCE_RE}_?(.*)", re.IGNORECASE
    )

    def __init__(self, filename):
        """Init the instance by matching the regex to the given filename

        Arguments
        ---------
            filename: str, filename (not a path)
            >>> finfo = LasFilename("CE_108_0+000_1+100.laz")
            >>> finfo.strada_name == "CE_108"
            True
            >>> finfo = LasFilename("some/kind/ok/path/CE_108_0+000_1+100.laz")
            >>> finfo.strada_name == "CE_108"
            True
            >>> finfo = LasFilename("some\\kind\\ok\\path\\CE_108_0+000_1+100.laz")
            >>> finfo.strada_name == "CE_108"
            True

        Raises
        ------
            RuntimeError if the filename does not match the regex used to parse the
            filename
        """
        groups = self.matcher.match(filename)
        if groups is None:
            raise RuntimeError(f"{filename} does not match the expected format")
        self.filename = filename
        self.strada_name = groups[1]
        self.lot = groups[2]
        self.km_start = int(groups[3])
        self.meter_start = int(groups[4])
        self.km_end = int(groups[5])
        self.meter_end = int(groups[6])

        rest = groups[7]
        if not rest:
            self.suffix, self.extension = None, None
        else:
            dot_pos = rest.rfind(".")
            if dot_pos == -1:
                self.suffix, self.extension = rest, None
            else:
                self.suffix = None if not rest[:dot_pos] else rest[:dot_pos]
                self.extension = (
                    None if not rest[dot_pos + 1 :] else rest[dot_pos + 1 :]
                )

        if self.distance < 0.0:
            raise RuntimeError(
                "Filename '{}' has a negative distance of {}".format(
                    filename, self.distance
                )
            )

    @classmethod
    def from_path(cls, path):
        return cls(Path(path).name)

    @property
    def start_dist(self):
        return (self.km_start * 1000) + self.meter_start

    @property
    def end_dist(self):
        return (self.km_end * 1000) + self.meter_end

    @property
    def distance(self):
        """Returns the distance extracted from the filename

        >>> finfo = LasFilename("CE_108_0+000_1+100.laz") # Ok
        >>> finfo.distance == 1100.0
        True
        """
        return self.end_dist - self.start_dist


def get_strada_name(file_name):
    return LasFilename(file_name).strada_name
